import xml.etree.ElementTree as ET

def validate_xml(xml_string):
    try:
        ET.fromstring(xml_string)
        return True
    except ET.ParseError:
        return False

# Example usage
xml_input = "<root><child>data</child></root>"
if validate_xml(xml_input):
    print("XML is valid")
else:
    print("XML is invalid")